package com.restaurantcraft.network; import com.restaurantcraft.blockentity.RestaurantManagementBlockEntity; import net.minecraft.core.BlockPos; import net.minecraft.network.FriendlyByteBuf; import net.minecraft.server.level.ServerPlayer; import net.minecraftforge.network.NetworkEvent; import java.util.function.Supplier; public record C2SDetectAreaPacket(BlockPos pos){ public static void encode(C2SDetectAreaPacket p,FriendlyByteBuf b){b.writeBlockPos(p.pos);} public static C2SDetectAreaPacket decode(FriendlyByteBuf b){return new C2SDetectAreaPacket(b.readBlockPos());} public static void handle(C2SDetectAreaPacket p,Supplier<NetworkEvent.Context> c){c.get().enqueueWork(()->{ServerPlayer sp=c.get().getSender(); if(sp!=null&&sp.level().getBlockEntity(p.pos) instanceof RestaurantManagementBlockEntity be&&be.canAccess(sp)){ be.detectArea(); }}); c.get().setPacketHandled(true);} }
